class Solution:
    def subtreeWithAllDeepest(self, root):
        from collections import deque
        if not root:
            return None
        depth = {root: 0}
        parent = {}
        q = deque([root])
        max_depth = 0
        while q:
            node = q.popleft()
            d = depth[node]
            if d > max_depth:
                max_depth = d
            for child in (node.left, node.right):
                if child:
                    depth[child] = d + 1
                    parent[child] = node
                    q.append(child)
        deepest = [node for node, d in depth.items() if d == max_depth]
        def ancestors(node):
            chain = []
            while node is not None:
                chain.append(node)
                node = parent.get(node)
            return chain
        def lca(u, v):
            au = ancestors(u)
            av = set(ancestors(v))
            for node in au:
                if node in av:
                    return node
            return None
        current = deepest[0]
        for node in deepest[1:]:
            current = lca(current, node)
        return current

