class Solution:
    def subtreeWithAllDeepest(self, root):
        def dfs(node):
            if not node:
                return 0, None
            ld, lt = dfs(node.left)
            rd, rt = dfs(node.right)
            if ld == rd:
                return ld + 1, node
            if ld > rd:
                return ld + 1, lt
            return rd + 1, rt
        return dfs(root)[1]

